#include <stdio.h>

int main(){
    int T;
    if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N;
        if(scanf("%d",&N)!=1) break;
        if(N%2==0 && N%5==0)
            printf("Even and Divisible by 5\n");
        else
            printf("Not Even or Not Divisible by 5\n");
    }
    return 0;
}

