import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        n = int(data[idx]); idx+=1
        if n%2==0 and n%5==0:
            out.append("Even and Divisible by 5")
        else:
            out.append("Not Even or Not Divisible by 5")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

